"use strict";(self.webpackChunkwoodpecker=self.webpackChunkwoodpecker||[]).push([["3066"],{96975(e){e.exports=JSON.parse('{"name":"S3 Cache","slug":"s3-cache","url":"https://codeberg.org/landre/woodpecker-plugins/cache","description":"Cache file or folders to S3-compatible storage","docs":"<h1>Overview</h1>\\n<p>This plugin caches a file of folder to S3-compatible storage, like AWS S3 or Cloudflare R2</p>\\n<h2>Features</h2>\\n<ul>\\n<li>Customizable cache keys</li>\\n<li>Optional gzip compression (enabled by default)</li>\\n</ul>\\n<p>Note: automatic expiry is not supported, use your S3 provider\'s configuration tools</p>\\n<h2>Settings</h2>\\n<table>\\n<thead>\\n<tr>\\n<th>Settings Name</th>\\n<th>Default</th>\\n<th>Description</th>\\n</tr>\\n</thead>\\n<tbody><tr>\\n<td><code>action</code></td>\\n<td><em>none</em></td>\\n<td>The action to perform. Supported values: <code>download</code>, <code>upload</code>, <code>clear</code></td>\\n</tr>\\n<tr>\\n<td><code>bucket</code></td>\\n<td><em>none</em></td>\\n<td>The bucket name</td>\\n</tr>\\n<tr>\\n<td><code>path</code></td>\\n<td><em>none</em></td>\\n<td>The file or directory to store as cache</td>\\n</tr>\\n<tr>\\n<td><code>key</code></td>\\n<td><code>{{branch}}-{{arch}}</code></td>\\n<td>The cache key, will be used as a subdirectory name. Arch will be set to the current architecture (<code>uname -m</code>) and the branch is the current branch (<code>$CI_COMMIT_SOURCE_BRANCH</code> if set, <code>$CI_COMMIT_BRANCH</code> for commits and <code>$CI_REPO_DEFAULT_BRANCH</code> for other events)</td>\\n</tr>\\n<tr>\\n<td><code>key_suffix</code></td>\\n<td><em>none</em></td>\\n<td>A custom suffix to add to the cache key</td>\\n</tr>\\n<tr>\\n<td><code>target_path</code></td>\\n<td><code>$CI_REPO</code></td>\\n<td>The path to the directory in the object storage to store the cache in</td>\\n</tr>\\n<tr>\\n<td><code>access_key_id</code></td>\\n<td><em>none</em></td>\\n<td>S3 Access Key ID</td>\\n</tr>\\n<tr>\\n<td><code>secret_access_key</code></td>\\n<td><em>none</em></td>\\n<td>S3 Secret Access Key</td>\\n</tr>\\n<tr>\\n<td><code>region</code></td>\\n<td><code>auto</code></td>\\n<td>S3 region</td>\\n</tr>\\n<tr>\\n<td><code>overwrite</code></td>\\n<td><code>true</code></td>\\n<td>Unset to avoid overwriting existing files in <code>download</code> mode</td>\\n</tr>\\n<tr>\\n<td><code>url</code></td>\\n<td><em>none</em></td>\\n<td>S3 API URL (leave empty for AWS S3)</td>\\n</tr>\\n<tr>\\n<td><code>compress</code></td>\\n<td><code>true</code></td>\\n<td>Unset to disable compression before sending (if you care more about CI speed than storage size)</td>\\n</tr>\\n<tr>\\n<td><code>debug</code></td>\\n<td><code>false</code></td>\\n<td>Set to enable debug logging</td>\\n</tr>\\n</tbody></table>\\n<h2>Examples</h2>\\n<pre><code class=\\"language-yaml\\">- name: cache\\n  image: quay.io/landre/woodpecker/cache\\n  settings:\\n    action: download\\n    bucket: woodpecker-cache\\n    access_key_id:\\n      from_secret: s3_access_key_id\\n    secret_access_key:\\n      from_secret: s3_secret_access_key\\n    path: node_modules\\n  when:\\n    branch: ${CI_REPO_DEFAULT_BRANCH}\\n    event: push\\n  failure: ignore # Ignore failure to avoid stopping the CI if the cache doesn\'t exist yet\\n</code></pre>\\n","tags":["cache","s3"],"author":"Loric Andr\xe9","containerImage":"codeberg.org/landre/woodpecker/cache","verified":false}')}}]);